import random

class General:
 def __init__(self, is_loyal):
 self.is_loyal = is_loyal
 self.decision = None

 def send_message(self):
 if self.is_loyal:
 return 'attack' if random.random() < 0.5 else 'retreat'
 else:
 return 'attack' if random.random() < 0.5 else 'retreat'

 def receive_message(self, message):
 if self.decision is None:
 self.decision = message
 elif self.decision != message:
 print('Conflict detected!')

# Initialize generals
num_generals = 10
num_traitors = 3

generals = [General(True) for _ in range(num_generals - num_traitors)] + [General(False) for _ in range(num_traitors)]

# Simulate communication
for general in generals:
 message = general.send_message()
 for other_general in generals:
 if other_general != general:
 other_general.receive_message(message)

# Check for consensus
consensus = None
for general in generals:
 if consensus is None:
 consensus = general.decision
 elif consensus != general.decision:
 print('No consensus reached!')
 break
else:
 print('Consensus reached:', consensus)

#include <stdio.h>
#include <stdlib.h>
#include <time.h>

#define NUM_GENERALS 10
#define NUM_TRAITORS 3

typedef struct General {
 int is_loyal;
 char decision;
} General;

char send_message(General general) {
 if (general.is_loyal) {
 return (rand() % 2 == 0) ? 'a' : 'r';
 } else {
 return (rand() % 2 == 0) ? 'a' : 'r';
 }
}

void receive_message(General* general, char message) {
 if (general->decision == '\0') {
 general->decision = message;
 } else if (general->decision != message) {
 printf('Conflict detected!');
 }
}

int main() {
 srand(time(NULL));

 General generals[NUM_GENERALS];
 for (int i = 0; i < NUM_GENERALS - NUM_TRAITORS; i++) {
 generals[i].is_loyal = 1;
 }
 for (int i = NUM_GENERALS - NUM_TRAITORS; i < NUM_GENERALS; i++) {
 generals[i].is_loyal = 0;
 }

 for (int i = 0; i < NUM_GENERALS; i++) {
 char message = send_message(generals[i]);
 for (int j = 0; j < NUM_GENERALS; j++) {
 if (i != j) {
 receive_message(&generals[j], message);
 }
 }
 }

 char consensus = '\0';
 for (int i = 0; i < NUM_GENERALS; i++) {
 if (consensus == '\0') {
 consensus = generals[i].decision;
 } else if (consensus != generals[i].decision) {
 printf('No consensus reached!');
 return 1;
 }
 }
 printf('Consensus reached: %c', consensus);
 return 0;
}
